<div wire:poll.visible.10s>
    @if ($hasEvent)
        <style>
            .section-path {
                transition: filter 0.15s ease, stroke-width 0.15s ease, stroke 0.15s ease, opacity 0.3s ease;
                cursor: pointer;
            }
            .section-path.section-hover {
                stroke: #fff !important;
                stroke-width: 3px !important;
                filter: drop-shadow(0 0 6px rgba(0,0,0,0.5)) !important;
            }
            .section-label {
                display: none;
                fill: currentColor;
                font-weight: 700;
                text-anchor: middle;
                dominant-baseline: central;
                pointer-events: none;
                paint-order: stroke;
                stroke: oklch(var(--b1));
                stroke-width: 3px;
                stroke-linecap: round;
                stroke-linejoin: round;
            }
        </style>

        <x-card class="shadow-md">
            <div class="text-center mb-4">
                <h2 class="text-xl font-bold">Section Map</h2>
                <p class="text-sm text-base-content/70">{{ $sectionsWorked }}/{{ $totalSections }} Sections &middot; {{ $totalQsos }} QSOs</p>
            </div>

            <div
                x-data="{
                    view: 'all',
                    colorMode: 'band',
                    highlightSection: null,
                    hoverSection: null,
                    pinnedSection: null,
                    lastPointerType: 'mouse',
                    hoverTimer: null,
                    tooltipX: 0,
                    tooltipY: 0,
                    get sectionData() { return $wire.sectionData },
                    get maxCount() { return $wire.maxCount },

                    callAreas: [1,2,3,4,5,6,7,8,9,0],
                    sectionGroups: {},

                    init() {
                        const savedView = sessionStorage.getItem('section_map_view');
                        const savedColorMode = sessionStorage.getItem('section_map_color_mode');
                        if (savedView) this.view = savedView;
                        if (savedColorMode) this.colorMode = savedColorMode;

                        this.$watch('view', (value) => sessionStorage.setItem('section_map_view', value));
                        this.$watch('colorMode', (value) => sessionStorage.setItem('section_map_color_mode', value));

                        this.$nextTick(() => {
                            this.$el.querySelectorAll('g[id^=w] > path.section-path').forEach(path => {
                                this.sectionGroups[path.id] = path.parentNode.id;
                            });
                        });

                        this.$watch('highlightSection', (newVal, oldVal) => {
                            if (oldVal) {
                                const oldEl = document.getElementById(oldVal);
                                if (oldEl) oldEl.classList.remove('section-hover');
                            }
                            if (newVal) {
                                const newEl = document.getElementById(newVal);
                                if (newEl) {
                                    newEl.classList.add('section-hover');
                                    // Delay DOM manipulation to let event chain complete
                                    setTimeout(() => {
                                        if (this.highlightSection === newVal) {
                                            const parent = newEl.parentNode;
                                            if (parent) {
                                                parent.appendChild(newEl);
                                                const grandparent = parent.parentNode;
                                                if (grandparent) grandparent.appendChild(parent);
                                            }
                                        }
                                    }, 0);
                                }
                            }
                        });
                    },

                    getViewBox() {
                        if (this.view === 'us') return '340 425 1200 675';
                        if (this.view === 'ca') return '395 15 1200 675';
                        if (this.view.startsWith('w')) {
                            const group = document.getElementById(this.view);
                            if (group) {
                                const bbox = group.getBBox();
                                const pad = 30;
                                return `${bbox.x - pad} ${bbox.y - pad} ${bbox.width + pad * 2} ${bbox.height + pad * 2}`;
                            }
                        }
                        return '0 0 1920 1080';
                    },

                    startHover(section) {
                        clearTimeout(this.hoverTimer);
                        this.highlightSection = section;
                        this.hoverTimer = setTimeout(() => { this.hoverSection = section; }, 200);
                    },

                    clearHover() {
                        clearTimeout(this.hoverTimer);
                        this.highlightSection = this.pinnedSection;
                        this.hoverSection = this.pinnedSection;
                    },

                    handlePointerMove(event) {
                        if (event.pointerType === 'touch') return;
                        const target = event.target.closest('.section-path');
                        const section = target?.id;
                        this.tooltipX = event.clientX;
                        this.tooltipY = event.clientY;
                        if (section) {
                            if (this.highlightSection !== section) {
                                this.startHover(section);
                            }
                        } else if (this.highlightSection) {
                            this.clearHover();
                        }
                    },

                    handleTouchTap(event) {
                        if (this.lastPointerType !== 'touch') return;
                        const target = event.target.closest('.section-path');
                        const section = target?.id;
                        if (section) {
                            if (this.pinnedSection === section) {
                                this.pinnedSection = null;
                                this.highlightSection = null;
                                this.hoverSection = null;
                            } else {
                                this.pinnedSection = section;
                                this.highlightSection = section;
                                this.hoverSection = section;
                                this.tooltipX = event.clientX;
                                this.tooltipY = event.clientY;
                            }
                        } else {
                            this.pinnedSection = null;
                            this.highlightSection = null;
                            this.hoverSection = null;
                        }
                    },

                    handleWindowClick(event) {
                        if (this.lastPointerType !== 'touch' || !this.pinnedSection) return;
                        if (!event.target.closest('svg')) {
                            this.pinnedSection = null;
                            this.highlightSection = null;
                            this.hoverSection = null;
                        }
                    },

                    getTooltipStyle() {
                        const pad = 12;
                        const estW = 220;
                        const estH = 60;
                        const x = this.tooltipX + pad + estW > window.innerWidth
                            ? this.tooltipX - estW - pad
                            : this.tooltipX + pad;
                        const y = this.tooltipY + pad + estH > window.innerHeight
                            ? this.tooltipY - estH - pad
                            : this.tooltipY + pad;
                        return { left: x + 'px', top: y + 'px' };
                    },


                    timeAgo(ts) {
                        if (!ts) return null;
                        const diff = Math.floor(Date.now() / 1000) - ts;
                        if (diff < 60) return 'just now';
                        if (diff < 3600) {
                            const m = Math.floor(diff / 60);
                            return m + (m === 1 ? ' minute ago' : ' minutes ago');
                        }
                        if (diff < 86400) {
                            const h = Math.floor(diff / 3600);
                            return h + (h === 1 ? ' hour ago' : ' hours ago');
                        }
                        const d = Math.floor(diff / 86400);
                        return d + (d === 1 ? ' day ago' : ' days ago');
                    },

                    bandHsl: {
                        // HF bands — each a distinct hue, ~50-90° apart
                        '160m': [355, 78, 50],  // Crimson Red
                        '80m':  [25,  90, 53],  // Vivid Orange
                        '40m':  [52,  87, 45],  // Amber (darkened for legibility)
                        '20m':  [140, 62, 40],  // Forest Green
                        '15m':  [200, 82, 46],  // Cerulean Blue
                        '10m':  [258, 68, 58],  // Indigo
                        // VHF / UHF / Satellite — all one shared color
                        '6m':       [308, 70, 54],
                        '2m':       [308, 70, 54],
                        '1.25m':    [308, 70, 54],
                        '70cm':     [308, 70, 54],
                        '33cm':     [308, 70, 54],
                        '23cm':     [308, 70, 54],
                        'Satellite':[308, 70, 54],  // Magenta-Purple
                    },

                    bandColor(band) {
                        const c = this.bandHsl[band];
                        return c ? `hsl(${c[0]}, ${c[1]}%, ${c[2]}%)` : '#d1d5db';
                    },

                    isDimmed(code) {
                        if (!this.view.startsWith('w')) return false;
                        return this.sectionGroups[code] !== this.view;
                    },

                    getSectionStyle(code) {
                        const data = this.sectionData[code];
                        const noData = !data || data.count === 0;
                        const dimmed = this.isDimmed(code);

                        if (noData) {
                            const base = { fill: '#d1d5db' };
                            if (dimmed) base.opacity = '0.15';
                            return base;
                        }

                        let fill;

                        if (this.colorMode === 'qso') {
                            const ratio = this.maxCount > 0 ? data.count / this.maxCount : 0;
                            const saturation = 20 + ratio * 50;
                            const lightness = 85 - ratio * 45;
                            fill = `hsl(130, ${saturation}%, ${lightness}%)`;
                        } else if (this.colorMode === 'time') {
                            const t = data.latestQsoTime;
                            if (!t) {
                                fill = '#d1d5db';
                            } else {
                                const ageSeconds = Math.floor(Date.now() / 1000) - t;
                                const minAge = 300;      // 5 minutes
                                const maxAge = 43200;    // 12 hours
                                const clamped = Math.max(minAge, Math.min(maxAge, ageSeconds));
                                const ratio = (clamped - minAge) / (maxAge - minAge);
                                const hue = 130 - ratio * 130; // 130=green (fresh) → 0=red (stale)
                                fill = ageSeconds < minAge
                                    ? `hsl(130, 65%, 45%)`
                                    : `hsl(${hue}, 65%, 50%)`;
                            }
                        } else {
                            const bandCounts = data.bandCounts || {};
                            const entries = Object.entries(bandCounts);
                            if (entries.length === 0) return { fill: '#d1d5db' };

                            const dominant = entries.reduce((a, b) => b[1] > a[1] ? b : a)[0];
                            const hsl = this.bandHsl[dominant];
                            const numBands = entries.length;

                            if (!hsl) {
                                fill = '#d1d5db';
                            } else if (numBands >= 3) {
                                fill = `hsl(${hsl[0]}, ${hsl[1]}%, ${hsl[2] - 10}%)`;
                            } else if (numBands >= 2) {
                                fill = `hsl(${hsl[0]}, ${hsl[1]}%, ${hsl[2]}%)`;
                            } else {
                                fill = `hsl(${hsl[0]}, ${Math.round(hsl[1] * 0.5)}%, ${hsl[2] + 15}%)`;
                            }
                        }

                        const style = { fill };

                        if (dimmed) style.opacity = '0.15';

                        return style;
                    }
                }"
                @click.window="handleWindowClick($event)"
            >
                <div class="flex flex-wrap justify-center gap-2 mb-3">
                    <div class="join">
                        <button class="join-item btn btn-sm" :class="view === 'all' ? 'btn-primary' : 'btn-ghost'" @click="view = 'all'; hoverSection = null">All</button>
                        <button class="join-item btn btn-sm" :class="view === 'us' ? 'btn-primary' : 'btn-ghost'" @click="view = 'us'; hoverSection = null">US</button>
                        <button class="join-item btn btn-sm" :class="view === 'ca' ? 'btn-primary' : 'btn-ghost'" @click="view = 'ca'; hoverSection = null">Canada</button>
                    </div>
                    <div class="join" x-show="view !== 'ca'" x-cloak>
                        <template x-for="n in callAreas" :key="n">
                            <button class="join-item btn btn-sm"
                                    :class="view === 'w' + n ? 'btn-primary' : 'btn-ghost'"
                                    @click="view = 'w' + n; hoverSection = null"
                                    x-text="'W' + n">
                            </button>
                        </template>
                    </div>
                </div>

                <div class="flex justify-center gap-1 mb-3">
                    <span class="text-xs text-base-content/70 self-center mr-1">Color:</span>
                    <div class="join">
                        <button class="join-item btn btn-xs" :class="colorMode === 'band' ? 'btn-secondary' : 'btn-ghost'" @click="colorMode = 'band'">Band</button>
                        <button class="join-item btn btn-xs" :class="colorMode === 'qso' ? 'btn-secondary' : 'btn-ghost'" @click="colorMode = 'qso'">QSO Count</button>
                        <button class="join-item btn btn-xs" :class="colorMode === 'time' ? 'btn-secondary' : 'btn-ghost'" @click="colorMode = 'time'">Recency</button>
                    </div>
                </div>

                <div class="w-full flex justify-center">
                    <svg
   class="w-full h-auto transition-[max-width] duration-300"
   :class="view.startsWith('w') ? 'max-w-3xl' : 'max-w-[1920px]'"
   :view-box.camel="getViewBox()"
   version="1.1"
   id="svg1"
   xml:space="preserve"
   xmlns="http://www.w3.org/2000/svg"
   @pointermove="handlePointerMove($event)"
   @pointerdown="lastPointerType = $event.pointerType"
   @click="handleTouchTap($event)"
   @pointerleave="clearHover()"
   role="img"
   aria-label="ARRL Section Map"
   focusable="false">
